UPDATE public.service_library
SET academy_metadata = '{"displayName":"Canada – CAIPS / GCMS Notes Request","shortDescription":"IRCC ATIP · GCMS notes · Refusal analysis · Case history","version":"v2.0","versionStatus":"Live","reviewStatus":"active","updatedLabel":"Updated 6 Jun 2026","learningLevel":"Beginner","learningMinutes":12,"policyAlert":{"active":true,"date":"6 Jun 2026","summary":"Confirm current ATIP eligibility, consent requirements, and processing timelines on canada.ca before ordering notes."},"alert":{"title":"Consent and requester eligibility required","body":"GCMS notes usually require an eligible requester in Canada or proper consent from the applicant. Do not request without signed authorization."},"tags":[{"label":"Active service","variant":"success"},{"label":"Consent required","variant":"warning"},{"label":"30+ days","variant":"neutral"},{"label":"Online – ATIP","variant":"neutral"}],"chips":[{"label":"30+ days processing","variant":"neutral"},{"label":"CAD $5 approx","variant":"neutral"},{"label":"Refusal insight","variant":"success"},{"label":"Not an appeal","variant":"warning"}],"kpis":[{"label":"Processing time","value":"30d+","sub":"ATIP timelines vary","tone":"primary"},{"label":"Government fee","value":"CAD $5","sub":"Verify on canada.ca","tone":"warning"},{"label":"Our completion rate","value":"98%","sub":"Consent-driven service","tone":"success"},{"label":"Required docs","value":"8","sub":"+ consent form","tone":"violet"},{"label":"Consultancy fee","value":"See fee tab","sub":"+ govt only","tone":"primary"}],"about":[{"label":"Description","value":"Access to Information and Privacy request for CAIPS/GCMS notes, used to review officer notes, refusal rationale, application status, and case history for Canadian immigration files."},{"label":"Eligible applicants","value":"Applicant with signed consent · Eligible requester in Canada where required · Correct IRCC application identifiers · Identity proof"},{"label":"Service scope","value":"GCMS notes provide records and officer comments but do not overturn a refusal or speed up processing.","warning":true},{"label":"Key authority","value":"Immigration, Refugees and Citizenship Canada (IRCC) and Government of Canada ATIP Online Request Service"},{"label":"After release","value":"Counselor reviews notes for refusal reasons, missing evidence, credibility concerns, and next application strategy."}],"eligibility":[{"criterion":"Signed consent from applicant or authorized person","met":true,"note":"Use current consent form"},{"criterion":"Requester eligibility confirmed for ATIP submission","met":true},{"criterion":"Applicant identity details match IRCC records","met":true},{"criterion":"Application number, UCI, or file details available","met":true},{"criterion":"Refusal letter or application history collected where relevant","met":true},{"criterion":"Applicant understands notes are not an appeal","met":true},{"criterion":"Privacy authorization and service agreement on file","met":true},{"criterion":"Correct department and record type selected in ATIP portal","met":true},{"criterion":"Delivery email and client contact details verified","met":true}],"redFlagsBanner":"Do not order GCMS notes without consent, correct identifiers, and clear expectations about what notes can and cannot do.","redFlags":[{"title":"No signed consent","description":"Applicant has not authorized the requester to access personal immigration records.","fix":"Collect current signed consent and identity proof before submitting","severity":"High"},{"title":"Requester not eligible","description":"ATIP requester may not meet Canada presence or status requirements for access request.","fix":"Use eligible requester or correct Privacy Act route as applicable","severity":"High"},{"title":"Wrong application identifiers","description":"UCI, application number, name spelling, or date of birth does not match IRCC record.","fix":"Cross-check refusal letter, portal screenshots, and passport before filing","severity":"Common"},{"title":"Client expects reversal","description":"Client believes ordering notes will reopen or approve the case.","fix":"Explain notes are informational and plan separate reconsideration or reapplication if needed","severity":"Very common"},{"title":"Urgent deadline missed","description":"Appeal, judicial review, or school deferral deadline may arrive before notes.","fix":"Escalate immediately; do not wait for notes if legal deadline is near","severity":"High"},{"title":"Wrong department selected","description":"Request submitted to the wrong institution or for wrong record type.","fix":"Select IRCC and specify immigration application records","severity":"Medium"},{"title":"Outdated consent form","description":"Consent form is missing signature, date, representative details, or applicant data.","fix":"Reissue consent form and verify every required field","severity":"Common"}],"faqs":[{"q":"What are GCMS notes?","a":"They are internal immigration records and officer notes from IRCC systems, often used to understand refusals or case status."},{"q":"Are CAIPS and GCMS the same?","a":"Clients often use the terms together. GCMS is the modern system most IRCC notes come from; CAIPS is an older term still used colloquially."},{"q":"How long do notes take?","a":"ATIP requests are commonly targeted around 30 days, but extensions and delays happen. Check the official ATIP process."},{"q":"Can GCMS notes overturn a refusal?","a":"No. Notes help diagnose reasons. Any reconsideration, appeal, judicial review, or reapplication is separate."},{"q":"Who can request notes?","a":"Eligibility depends on access to information and privacy rules. Often an eligible requester in Canada submits with applicant consent."},{"q":"What documents are needed?","a":"Signed consent, applicant identity details, passport, refusal letter or application details, UCI, application number, and requester information."},{"q":"Can we order notes for an application still in process?","a":"Yes, but notes may be limited or outdated by the time received. Manage expectations."},{"q":"Will notes show the exact reason for refusal?","a":"Often they provide more detail than the refusal letter, but some information may be redacted or procedural."},{"q":"Should we wait for notes before reapplying?","a":"For refusals, notes are helpful. But if intake, visa, or legal deadlines are urgent, escalate and decide strategically."},{"q":"Can family members sign for the applicant?","a":"Only if legally authorized. Otherwise each adult applicant generally signs their own consent."},{"q":"What is Description for this service?","a":"Access to Information and Privacy request for CAIPS/GCMS notes, used to review officer notes, refusal rationale, application status, and case history for Canadian immigration files."},{"q":"What is Eligible applicants for this service?","a":"Applicant with signed consent · Eligible requester in Canada where required · Correct IRCC application identifiers · Identity proof"},{"q":"What is Service scope for this service?","a":"GCMS notes provide records and officer comments but do not overturn a refusal or speed up processing."},{"q":"Important note on Service scope?","a":"GCMS notes provide records and officer comments but do not overturn a refusal or speed up processing."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC) and Government of Canada ATIP Online Request Service"},{"q":"What is After release for this service?","a":"Counselor reviews notes for refusal reasons, missing evidence, credibility concerns, and next application strategy."},{"q":"Is Signed consent from applicant or authorized person required?","a":"Use current consent form"},{"q":"Is Requester eligibility confirmed for ATIP submission required?","a":"Requester eligibility confirmed for ATIP submission is typically required."},{"q":"Is Applicant identity details match IRCC records required?","a":"Applicant identity details match IRCC records is typically required."},{"q":"Is Application number, UCI, or file details available required?","a":"Application number, UCI, or file details available is typically required."},{"q":"Is Refusal letter or application history collected where relevant required?","a":"Refusal letter or application history collected where relevant is typically required."},{"q":"Is Applicant understands notes are not an appeal required?","a":"Applicant understands notes are not an appeal is typically required."},{"q":"Is Privacy authorization and service agreement on file required?","a":"Privacy authorization and service agreement on file is typically required."},{"q":"Is Correct department and record type selected in ATIP portal required?","a":"Correct department and record type selected in ATIP portal is typically required."},{"q":"Is Delivery email and client contact details verified required?","a":"Delivery email and client contact details verified is typically required."},{"q":"What is the Processing time?","a":"30d+ — ATIP timelines vary"},{"q":"What is the Government fee?","a":"CAD $5 — Verify on canada.ca"},{"q":"What is the Our completion rate?","a":"98% — Consent-driven service"},{"q":"What is the Required docs?","a":"8 — + consent form"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}],"compliance":["Signed consent and privacy authorization must be on file before ATIP request","Never promise that notes will reverse a decision or guarantee future approval","Protect GCMS notes as sensitive personal information","Fee quotes must separate consultancy, government, and third-party costs"],"proTips":["Collect refusal letter and portal screenshots before drafting ATIP request","Use exact passport name, date of birth, UCI, and application number","Warn clients that notes may be delayed or partially redacted","Review notes against the original application package, not in isolation","Flag judicial review or appeal deadlines before waiting for notes","Store released notes securely with restricted access"],"postApproval":["Download and save GCMS notes securely in the client binder","Summarize officer concerns in plain language for the client","Map each refusal concern to evidence needed for next filing","Schedule strategy call for reapplication, reconsideration, or legal referral","Delete or restrict duplicate copies according to privacy policy"],"performance":{"ourRate":98,"industryRate":92,"stats":[{"label":"Files this year","value":"154"},{"label":"Released","value":"151"},{"label":"Returned","value":"2"},{"label":"Withdrawn","value":"1"}]},"approvalFactors":[{"label":"Completion vs benchmark","ours":98,"benchmark":92},{"label":"Consent accuracy","ours":97,"benchmark":88},{"label":"Identifier matching","ours":96,"benchmark":85},{"label":"Actionable review notes","ours":90,"benchmark":75}],"timeline":[{"weeks":"1","title":"Consent, identity, and file details collection"},{"weeks":"1","title":"ATIP portal submission"},{"weeks":"4–8","title":"Government processing and possible extension"},{"weeks":"5–9","title":"Notes review and strategy summary"}],"relatedServices":[{"label":"Canada – Student Visa","libraryId":""},{"label":"Canada – Visitor Visa","libraryId":""},{"label":"Canada – Express Entry PR","libraryId":""}],"changelog":[{"version":"v2.0","date":"7 Jun 2026","author":"Service Library","summary":"Expanded FAQs to 30 counselor Q&A pairs."},{"version":"v2.0","date":"6 Jun 2026","author":"Service Library","summary":"Added 75 levelled quiz questions (Level 1–3, 25+ each) and expanded counselor content."},{"version":"v1.0","date":"6 Jun 2026","author":"Service Library","summary":"Initial CAIPS / GCMS notes counselor content."}],"staffNotes":[{"author":"Documentation team","date":"6 Jun 2026","text":"GCMS service is privacy-sensitive. No consent, no request. Notes support strategy but are not a remedy by themselves."}],"resources":[{"title":"Government of Canada — ATIP Online Request","url":"https://atip-aiprp.apps.gc.ca/atip/welcome.do","description":"Official online access to information request portal"},{"title":"IRCC — Access to information and privacy","url":"https://www.canada.ca/en/immigration-refugees-citizenship/corporate/transparency/access-information-privacy.html","description":"IRCC ATIP overview"},{"title":"Government of Canada — Make an access to information request","url":"https://www.canada.ca/en/treasury-board-secretariat/services/access-information-privacy/access-information/request-information.html","description":"Who can request and how the process works"},{"title":"Government of Canada — Privacy Act requests","url":"https://www.canada.ca/en/treasury-board-secretariat/services/access-information-privacy/privacy/request-personal-information.html","description":"Requesting personal information under privacy rules"},{"title":"IRCC — Use of a representative","url":"https://www.canada.ca/en/immigration-refugees-citizenship/services/immigration-citizenship-representative/use-representative.html","description":"Representative and authorization guidance"},{"title":"Government of Canada — Access to Information Act","url":"https://laws-lois.justice.gc.ca/eng/acts/A-1/","description":"Legal framework for access requests"}],"quiz":[{"level":1,"question":"What are CAIPS or GCMS notes?","options":["Internal immigration file notes released through an access request","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"CAIPS is older terminology; GCMS notes help explain IRCC file history."},{"level":1,"question":"What does GCMS stand for?","options":["Global Case Management System","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS is IRCC''s case management system."},{"level":1,"question":"Why request GCMS notes after refusal?","options":["To understand officer concerns and refusal reasoning","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes can reveal details beyond a standard refusal letter."},{"level":1,"question":"What does ATIP stand for?","options":["Access to Information and Privacy","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"ATIP is the process for requesting government records."},{"level":1,"question":"Who can usually make an ATIP request directly?","options":["A Canadian citizen, permanent resident, or person/entity in Canada","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access requests usually require a qualified requester."},{"level":1,"question":"What is a consent form used for?","options":["Authorizing release of the applicant''s information to the requester","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Consent is needed when someone requests another person''s personal records."},{"level":1,"question":"What is the common ATIP response target?","options":["About 30 days, subject to extensions","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"ATIP is associated with a 30-day target, but extensions and delays occur."},{"level":1,"question":"Do GCMS notes overturn a refusal by themselves?","options":["No, they provide information only","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes are diagnostic and do not reopen or approve a file automatically."},{"level":1,"question":"Which file types can notes help analyze?","options":["Visitor, study, work, PR, sponsorship, and citizenship-related files","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS notes can be useful across many immigration file types."},{"level":1,"question":"What information helps locate a file?","options":["UCI, application number, name, and date of birth","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Accurate identifiers help locate the correct record."},{"level":1,"question":"What is a UCI?","options":["Unique Client Identifier","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"A UCI is an IRCC client number."},{"level":1,"question":"What can officer notes contain?","options":["Assessment comments, concerns, eligibility review, and processing history","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes may show how documents and eligibility were assessed."},{"level":1,"question":"Why might information be redacted?","options":["Law permits withholding sensitive or third-party information","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access laws allow exemptions for security, privacy, and other protected information."},{"level":1,"question":"What is CAIPS older terminology linked to?","options":["Legacy immigration computer notes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"People still say CAIPS, but many modern records are GCMS."},{"level":1,"question":"When are GCMS notes especially helpful?","options":["After a refusal or long delay where reasons are unclear","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes can identify real issues in refusals or delays."},{"level":1,"question":"What fee is commonly associated with access requests?","options":["A small government fee","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access to Information requests usually involve a modest fee."},{"level":1,"question":"Which document proves consent for a representative request?","options":["Signed consent from the applicant","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Signed consent authorizes disclosure to the requester."},{"level":1,"question":"What is refusal analysis?","options":["Reviewing the decision record to identify weaknesses and next steps","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Analysis compares reasons, documents, and notes."},{"level":1,"question":"Can notes show eligibility status?","options":["They may show assessments such as eligibility, criminality, or security","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Internal statuses often appear, though some fields may be redacted."},{"level":1,"question":"Why must request details be accurate?","options":["Wrong details can delay or misdirect the request","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Accurate identifiers prevent incomplete results."},{"level":1,"question":"How does a refusal letter compare with GCMS notes?","options":["It usually gives a shorter summary","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS notes can provide more internal detail."},{"level":1,"question":"Which agency commonly holds IRCC application notes?","options":["Immigration, Refugees and Citizenship Canada","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"IRCC holds many immigration application records."},{"level":1,"question":"What can a representative do with notes?","options":["Advise on reapplication, reconsideration, or litigation strategy","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes support strategy but do not decide the case."},{"level":1,"question":"Why is the application number useful?","options":["It identifies the specific application","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Application numbers help target the exact file."},{"level":1,"question":"Which statement about notes is correct?","options":["They are useful but may be redacted, delayed, or limited","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes provide transparency but not every desired detail."},{"level":2,"question":"What is first before requesting notes for someone else?","options":["Obtain signed consent from the applicant","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Privacy rules require authorization for third-party release."},{"level":2,"question":"Which details should be collected for ATIP?","options":["Full name, date of birth, UCI, application number, and file type","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Complete identifiers help find the correct records."},{"level":2,"question":"Why choose the correct institution?","options":["The request must go to the department holding the records","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"IRCC notes should generally be requested from IRCC."},{"level":2,"question":"What should be reviewed with GCMS notes?","options":["The refusal letter and full submitted application package","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Comparing all records gives a better diagnosis."},{"level":2,"question":"Why can recent notes be incomplete?","options":["System updates may not capture every detail immediately","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Timing affects what appears in released notes."},{"level":2,"question":"How can notes help before reapplying?","options":["They target new evidence to actual officer concerns","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"A reapplication can be more focused and responsive."},{"level":2,"question":"What does a consent form commonly include?","options":["Applicant identity, requester details, signature, and scope","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Consent should clearly authorize release."},{"level":2,"question":"Why might ATIP extend beyond 30 days?","options":["Large volume, consultations, or allowed operational reasons","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Access laws permit extensions in certain cases."},{"level":2,"question":"Which field may reveal the deciding concern?","options":["Eligibility or final assessment comments","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Assessment comments often explain why the officer was not satisfied."},{"level":2,"question":"How are notes different from reconsideration?","options":["Notes disclose records; reconsideration asks IRCC to revisit a decision","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"They are separate processes."},{"level":2,"question":"When might CBSA notes be useful?","options":["When border, enforcement, or security records may be relevant","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Some records are held by CBSA rather than IRCC."},{"level":2,"question":"How should redactions be treated?","options":["Recognize legal limits and infer cautiously","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Redactions limit certainty."},{"level":2,"question":"Why is the original package important?","options":["It shows what evidence the officer had","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Analysis must consider the record before the decision-maker."},{"level":2,"question":"What can a criminality or medical status field indicate?","options":["A processing stage or assessment result","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS statuses can show progress or concerns in context."},{"level":2,"question":"How should weak-ties notes be used?","options":["Add specific home-country evidence and explain temporary purpose","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"New evidence should address the identified concern."},{"level":2,"question":"What does insufficient-funds language suggest?","options":["The officer was not satisfied finances supported the application","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Financial concerns need clearer credible evidence."},{"level":2,"question":"Why do timelines matter in refusal analysis?","options":["They separate facts before the decision from later changes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Old and new evidence support different strategies."},{"level":2,"question":"What if the wrong file is returned?","options":["Submit a corrected request with accurate identifiers","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Correct details help obtain the intended record."},{"level":2,"question":"Which next step may be time-sensitive?","options":["Judicial review deadline","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Court deadlines can be short and are not paused by ATIP."},{"level":2,"question":"Why not wait for notes if a legal deadline is near?","options":["Missing the deadline may eliminate that remedy","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"ATIP requests do not necessarily extend court deadlines."},{"level":2,"question":"What is a focused ATIP request?","options":["A request specifying the file, period, and records needed","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Focused requests reduce confusion."},{"level":2,"question":"What can an in-Canada requester do?","options":["Submit an access request with the applicant''s consent","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"A qualified requester can request records but cannot decide the case."},{"level":2,"question":"Which document anchors refusal analysis?","options":["The refusal letter with date and application number","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"The refusal letter identifies the specific decision."},{"level":2,"question":"Why might multiple ATIP requests be needed?","options":["Different applications or agencies may have separate records","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Complex histories can require targeted requests."},{"level":2,"question":"What should a refusal analysis conclude?","options":["Specific weaknesses, evidence gaps, and viable next options","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Useful analysis turns notes into practical strategy."},{"level":3,"question":"Why can notes be insufficient for judicial review alone?","options":["Court review has its own record and legal reasonableness test","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"GCMS notes help strategy but do not replace litigation rules."},{"level":3,"question":"What is risky about assuming redacted security content is harmless?","options":["Missing content may affect admissibility analysis","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Redactions limit visibility into sensitive assessments."},{"level":3,"question":"How can notes reveal document credibility issues?","options":["They may mention verification concerns or inconsistencies","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Officer comments can point to authenticity concerns."},{"level":3,"question":"Why should reapplications not merely argue the officer was wrong?","options":["They should provide stronger evidence addressing concerns","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Fixing evidence gaps is usually more useful than disagreement alone."},{"level":3,"question":"What is a limitation for very recent applications?","options":["Notes may show little activity if no substantive review occurred","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes only reflect records created by extraction."},{"level":3,"question":"What can study permit notes expose?","options":["Doubts about study plan, finances, ties, or progression","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes clarify temporary resident concerns."},{"level":3,"question":"What can sponsorship notes expose?","options":["Relationship genuineness, document gaps, or interview concerns","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Family-class notes may show relationship and admissibility analysis."},{"level":3,"question":"What is the danger of using notes to craft false evidence?","options":["Misrepresentation and long-term inadmissibility","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes should guide truthful clarification only."},{"level":3,"question":"Why read notes with program law in mind?","options":["Officer concerns must be mapped to the legal test","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Good analysis connects facts, law, and reasoning."},{"level":3,"question":"What suggests reconsideration may be difficult?","options":["The refusal was based on missing evidence not submitted before decision","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Reconsideration is harder when the original record was incomplete."},{"level":3,"question":"When may reconsideration be more plausible?","options":["When evidence was overlooked or a clear error occurred","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Reconsideration is strongest on existing-record errors."},{"level":3,"question":"Why are extraction dates important?","options":["They show when the notes snapshot was generated","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"The generation date affects interpretation."},{"level":3,"question":"What is a common interpretation issue?","options":["Distinguishing boilerplate from officer-specific reasoning","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Not every GCMS line is a substantive finding."},{"level":3,"question":"Why can boilerplate refusal reasons mislead?","options":["They may not identify precise concerns without internal notes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Generic reasons often require deeper analysis."},{"level":3,"question":"What if notes contradict the refusal letter?","options":["Analyze both and consider legal advice on reasonableness or fairness","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Contradictions can matter in context."},{"level":3,"question":"Why do ATIP extensions matter strategically?","options":["They may delay notes beyond reapplication or court planning deadlines","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Timing affects how notes can be used."},{"level":3,"question":"Which notes are most useful for diagnosis?","options":["Latest eligibility and final decision comments","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Final comments usually contain the clearest reasoning."},{"level":3,"question":"What can a bring-forward date indicate?","options":["An internal file review or action date","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Internal dates are not guaranteed decision dates."},{"level":3,"question":"Why separate old evidence from new evidence?","options":["It matters whether the officer had the evidence when deciding","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Legal options differ based on the decision record."},{"level":3,"question":"What is a risk of filing repeated ATIP requests too broadly?","options":["Delays and unfocused records that are hard to analyze","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Targeted requests are usually more useful."},{"level":3,"question":"How can notes help identify unreasonable reasoning?","options":["They may show conclusions unsupported by the submitted record","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Legal review focuses on whether reasons and outcome are justified."},{"level":3,"question":"Why should applicants preserve submitted packages?","options":["They are needed to compare with officer notes","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Without the package, refusal analysis is incomplete."},{"level":3,"question":"What if notes show an officer misunderstood a document?","options":["A targeted reconsideration or reapplication explanation may address it","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"The response depends on timing and available remedies."},{"level":3,"question":"Why should analysis avoid overpromising based on notes?","options":["Notes can be partial, redacted, or ambiguous","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Responsible advice recognizes uncertainty."},{"level":3,"question":"What is the best advanced use of CAIPS/GCMS notes?","options":["Build an evidence-based strategy for reapplication, reconsideration, or review","A visa counterfoil","A work permit exemption code","A language test certificate"],"correctIndex":0,"explanation":"Notes are most useful when translated into a concrete next step."}],"donts":{"dos":["Collect signed consent before request","Verify UCI, application number, and name spelling","Explain notes are informational","Review notes against original submission","Protect records as sensitive personal data"],"donts":["Do not request without consent","Do not promise refusal reversal","Do not ignore appeal or judicial review deadlines","Do not submit with mismatched identifiers","Do not share notes with unauthorized parties"],"mistakes":["Missing applicant signature on consent","Wrong IRCC application number","Selecting wrong government institution","Waiting for notes despite urgent school deadline","Treating notes as a substitute for legal advice"]},"sampleDocs":[{"title":"Sample consent form (mock)","description":"Authorization for release of personal immigration information.","mimeType":"application/pdf","docKind":"compliance"},{"title":"Sample passport bio page (mock)","description":"Identity confirmation for applicant details.","mimeType":"image/jpeg","docKind":"identity"},{"title":"Sample refusal letter (mock)","description":"Used to match application number and refusal date.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample IRCC portal screenshot (mock)","description":"Shows application number, UCI, and submission status.","mimeType":"image/jpeg","docKind":"immigration"},{"title":"Sample requester proof of status (mock)","description":"Evidence for eligible requester where required.","mimeType":"application/pdf","docKind":"identity"},{"title":"Sample ATIP payment receipt (mock)","description":"Proof of government fee payment.","mimeType":"application/pdf","docKind":"financial"},{"title":"Sample GCMS notes release (mock)","description":"Redacted example of released officer notes.","mimeType":"application/pdf","docKind":"immigration"},{"title":"Sample refusal analysis memo (mock)","description":"Counselor summary mapping officer concerns to next steps.","mimeType":"application/pdf","docKind":"compliance"}],"navBucket":"visa","workingRights":{"applicant":{"summary":"Visitor visa (TRV) / super visa generally does not authorize work in Canada. Super visa allows extended stays with parents/grandparents of citizens/PRs but still no employment.","details":["Business visitor activities are limited — distinguish from work requiring work permit.","Super visa requires medical insurance and sponsor income proof."],"restrictions":["Employment without authorization is illegal","Study beyond short course may need study permit"],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","lastVerified":"Jun 2026"},"spouse":{"summary":"Spouse accompanying on visitor status cannot work unless they separately obtain an eligible work permit or change status.","details":["If spouse intends to work, assess study permit + SOWP or work permit pathways instead of visitor."],"restrictions":["Visitor record does not grant work rights"],"sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","lastVerified":"Jun 2026"}},"fullCostBreakdown":{"title":"Full cost breakdown — Canada – CAIPS / GCMS Notes Request","currency":"CAD","lastVerified":"Jun 2026","disclaimer":"Indicative costs for counselor discussions only. Government fees, tuition, and living amounts change — verify on official websites before quoting clients. Exchange rates affect INR equivalents.","sourceUrl":"https://www.canada.ca/en/immigration-refugees-citizenship.html","sections":[{"id":"fees","label":"Government & visa fees","items":[{"label":"Visitor visa (TRV)","amount":100,"unit":"per applicant","currency":"CAD","applicable":true},{"label":"Biometrics","amount":85,"unit":"per applicant","currency":"CAD","applicable":true},{"label":"Super visa (if applicable)","amount":100,"notes":"Plus medical insurance","currency":"CAD","applicable":true}]},{"id":"tuition","label":"Tuition & education costs","items":[{"label":"Tuition","applicable":f